class BridgeClient extends EventEmitter {
  private readonly client: HarnessClient;

  get rpc(): RpcClient {
    return this.client.rpc;
  }

  constructor(options: BridgeClientOptions) {
    super();
    this.client = new HarnessClient(options);

    this.client.on('event', (event: BridgeEvent) => {
      profiler.begin(`bridge.client.validate:${event.type}`, 'tui');
      const validated = validateBridgeEvent(event);
      if (!validated) {
        profiler.end(`bridge.client.validate:${event.type}`, 'tui');
        // Emit error event for UI handling - do NOT use console.error
        // as it breaks Ink's rendering and causes flickering
        const errorMsg = `Malformed event from bridge. Type: ${event?.type ?? 'undefined'}, Data: ${JSON.stringify(event?.data ?? {}).slice(0, 200)}`;
        this.emit('error', { message: errorMsg });
        return;
      }
      profiler.end(`bridge.client.validate:${event.type}`, 'tui');

      profiler.instant(`bridge.client.emit:${event.type}`, 'tui', 'p');
      this.emit('event', validated);
    });

    this.client.on('error', (payload) => {
      this.emit('error', payload);
    });

    this.client.on('close', () => {
      this.emit('close');
    });

    this.client.on('connection_state', (state: ConnectionState) => {
      this.emit('connection_state', state);
    });
  }

  async connect(): Promise<void> {
    return this.client.connect();
  }

  send(command: BridgeCommand): boolean {
    profiler.instant(`tui:send:${command.type}`, 'tui', 'p');
    return this.client.send(command as unknown as HarnessBridgeCommand);
  }

  close(): void {
    this.client.close();
  }
}

get rpc(): RpcClient {
    return this.client.rpc;
  }

close(): void {
    this.client.close();
  }

type ParserApi = {
  initParser: () => Promise<void>
  isParserInitialized: () => boolean
  languageForFile: (filePath: string) => SupportedLanguage | null
  createParser: (language: SupportedLanguage) => { parse: (source: string) => Tree | null }
}

function loadParserApi(): Promise<ParserApi | null> {
  if (parserApi) return Promise.resolve(parserApi)
  if (parserApiPromise) return parserApiPromise

  parserApiPromise = import('entity-graph')
    .then(async (mod) => {
      const api: ParserApi = {
        initParser: mod.initParser,
        isParserInitialized: mod.isParserInitialized,
        languageForFile: mod.languageForFile,
        createParser: mod.createParser,
      }
      parserApi = api

      try {
        await api.initParser()
      } catch {
        // tree-sitter WASM init failed — syntax highlighting will be disabled
      }

      return api
    })
    .catch(() => null)

  return parserApiPromise
}

function ensureParserInitStarted(): void {
  if (syntaxHighlightingDisabled) return
  if (!parserApi && !parserApiPromise) {
    void loadParserApi()
  }
}

function detectLanguage(lang: string | undefined): SupportedLanguage | null {
  const api = parserApi
  if (!api) return null

  if (!lang) return null

  const normalized = lang.toLowerCase().trim()

  // Check direct aliases
  if (LANGUAGE_ALIASES[normalized]) {
    return LANGUAGE_ALIASES[normalized]
  }

  // Try as extension
  const ext = normalized.startsWith('.') ? normalized : `.${normalized}`
  return api.languageForFile(`dummy${ext}`)
}

function isLanguageSupported(lang: string | undefined): boolean {
  if (syntaxHighlightingDisabled) return false
  const api = parserApi
  if (!api) {
    ensureParserInitStarted()
    return false
  }
  if (!api.isParserInitialized()) return false
  return detectLanguage(lang) !== null
}

function highlightCode(code: string | null, lang: string | undefined): string {
  if (syntaxHighlightingDisabled) {
    return code ?? ''
  }

  const api = parserApi
  if (!api) {
    ensureParserInitStarted()
    return code ?? ''
  }

  // Handle null/undefined input - return empty string
  if (code == null) return ''

  // Skip highlighting for empty code
  if (code.trim() === '') {
    return code
  }

  // Parser not ready yet — return plain text
  if (!api.isParserInitialized()) {
    return code
  }

  // Detect language
  const supportedLang = detectLanguage(lang)

  // For unsupported/unspecified languages, do not apply fallback background color.
  // Preserve raw code text so we never force a background in the TUI.
  if (!supportedLang) {
    return code
  }

  try {
    // Parse the code
    const parser = api.createParser(supportedLang)
    const tree = parser.parse(code)
    if (!tree) {
      return code
    }

    // Apply highlighting without background (syntax only)
    const highlighted = highlightTree(tree, code)

    // Return highlighted code without background
    return highlighted
  } catch (error) {
    // If parsing fails, return plain code without background
    return code
  }
}

function applyHighlights(
  source: string,
  highlights: Array<{ start: number; end: number; color: (text: string) => string }>
): string {
  // Track which character positions are colored and by which highlight
  const charColors: Array<((text: string) => string) | null> = new Array(source.length).fill(null)

  // Assign colors to characters (last highlight wins for overlaps)
  for (const h of highlights) {
    for (let i = h.start; i < h.end && i < source.length; i++) {
      charColors[i] = h.color
    }
  }

  // Build output with ANSI codes
  let result = ''
  let i = 0

  while (i < source.length) {
    const color = charColors[i]

    if (!color) {
      // No color, just add character
      result += source[i]
      i++
      continue
    }

    // Find run of same color
    const start = i
    while (i < source.length && charColors[i] === color) {
      i++
    }

    // Add colored text
    result += color(source.slice(start, i))
  }

  return result
}

interface EventBusProtocol {
  publish(event: AnyEvent): void;
  subscribe(type: AgentEventType, handler: (event: AnyEvent) => void): () => void;
  subscribeAll(handler: (event: AnyEvent) => void): () => void;
  /** Subscribe to events for a specific run */
  subscribeRun(runId: string, handler: (event: AnyEvent) => void): () => void;
  shutdown(): void;
}

class EventBus implements EventBusProtocol {
  private emitter = new EventEmitter();
  private runHandlers = new Map<string, Set<(event: AnyEvent) => void>>();
  private shutdownFlag = false;
  private readonly ALL_EVENTS = '__all__';

  private pendingEvents: Array<AnyEvent> = [];
  private flushScheduled = false;

  constructor() {
    this.emitter.setMaxListeners(100);
  }

  publish(event: AnyEvent): void {
    if (this.shutdownFlag) return;

    // Streaming events dispatch immediately - no batching delay
    // These are high-frequency, latency-sensitive events
    const isStreamingEvent = event.type === 'agent_message' || event.type === 'agent_reasoning';
    if (isStreamingEvent) {
      this.dispatchEvent(event);
      return;
    }

    this.pendingEvents.push(event);
    this.scheduleFlush();
  }

  private scheduleFlush(): void {
    if (this.flushScheduled) return;
    this.flushScheduled = true;
    queueMicrotask(() => this.flush());
  }

  private flush(): void {
    if (this.shutdownFlag) {
      this.pendingEvents = [];
      this.flushScheduled = false;
      return;
    }

    const batch = this.pendingEvents;
    this.pendingEvents = [];
    this.flushScheduled = false;

    for (const event of batch) {
      this.dispatchEvent(event);
    }

    if (this.pendingEvents.length > 0 && !this.flushScheduled) {
      this.scheduleFlush();
    }
  }

