function highlightCode(code: string | null, lang: string | undefined): string {
  if (syntaxHighlightingDisabled) {
    return code ?? ''
  }

  const api = parserApi
  if (!api) {
    ensureParserInitStarted()
    return code ?? ''
  }

  // Handle null/undefined input - return empty string
  if (code == null) return ''

  // Skip highlighting for empty code
  if (code.trim() === '') {
    return code
  }

  // Parser not ready yet — return plain text
  if (!api.isParserInitialized()) {
    return code
  }

  // Detect language
  const supportedLang = detectLanguage(lang)

  // For unsupported/unspecified languages, do not apply fallback background color.
  // Preserve raw code text so we never force a background in the TUI.
  if (!supportedLang) {
    return code
  }

  try {
    // Parse the code
    const parser = api.createParser(supportedLang)
    const tree = parser.parse(code)
    if (!tree) {
      return code
    }

    // Apply highlighting without background (syntax only)
    const highlighted = highlightTree(tree, code)

    // Return highlighted code without background
    return highlighted
  } catch (error) {
    // If parsing fails, return plain code without background
    return code
  }
}

function highlightTree(tree: Tree, source: string): string {
  const root = tree.rootNode

  // Check for parse errors (still try to highlight what we can)
  // Note: hasError is a property in tree-sitter binding
  const hasError = root.hasError

  // Collect all highlightable nodes with their ranges
  const highlights: Array<{ start: number; end: number; color: (text: string) => string }> = []

  // Walk the tree and collect nodes that have color mappings
  const walk = (node: Node) => {
    const color = getColorForNode(node.type)
    if (color && node.text.length > 0) {
      highlights.push({
        start: node.startIndex,
        end: node.endIndex,
        color,
      })
    }

    // Recursively walk ALL children (named and unnamed)
    // Keywords like 'function', 'return' are unnamed children
    for (let i = 0; i < node.childCount; i++) {
      walk(node.child(i)!)
    }
  }

  walk(root)

  // If no highlights found, return original code
  if (highlights.length === 0) {
    return source
  }

  // Sort highlights by start position
  highlights.sort((a, b) => a.start - b.start)

  // Build the output string with ANSI codes
  return applyHighlights(source, highlights)
}

function isLanguageSupported(lang: string | undefined): boolean {
  if (syntaxHighlightingDisabled) return false
  const api = parserApi
  if (!api) {
    ensureParserInitStarted()
    return false
  }
  if (!api.isParserInitialized()) return false
  return detectLanguage(lang) !== null
}

