function highlightCode(code: string | null, lang: string | undefined): string {
  if (syntaxHighlightingDisabled) {
    return code ?? ''
  }

  const api = parserApi
  if (!api) {
    ensureParserInitStarted()
    return code ?? ''
  }

  // Handle null/undefined input - return empty string
  if (code == null) return ''

  // Skip highlighting for empty code
  if (code.trim() === '') {
    return code
  }

  // Parser not ready yet — return plain text
  if (!api.isParserInitialized()) {
    return code
  }

  // Detect language
  const supportedLang = detectLanguage(lang)

  // For unsupported/unspecified languages, do not apply fallback background color.
  // Preserve raw code text so we never force a background in the TUI.
  if (!supportedLang) {
    return code
  }

  try {
    // Parse the code
    const parser = api.createParser(supportedLang)
    const tree = parser.parse(code)
    if (!tree) {
      return code
    }

    // Apply highlighting without background (syntax only)
    const highlighted = highlightTree(tree, code)

    // Return highlighted code without background
    return highlighted
  } catch (error) {
    // If parsing fails, return plain code without background
    return code
  }
}

